using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    [DataRow(10, 1, 5, 2, DisplayName = "10 items, page 1 of 2")]
    [DataRow(10, 2, 5, 2, DisplayName = "10 items, page 2 of 2")]
    [DataRow(7, 1, 3, 3, DisplayName = "7 items, page 1 of 3")]
    [DataRow(1, 1, 10, 1, DisplayName = "1 item, page 1 of 1")]
    public void Constructor_ValidInputs_SetsCorrectTotalPages(int count, int pageIndex, int pageSize, int expectedTotalPages)
    {
        // Arrange
        var items = new List<int>();

        // Act
        var list = new PaginatedList<int>(items, count, pageIndex, pageSize);

        // Assert
        Assert.AreEqual(expectedTotalPages, list.TotalPages);
        Assert.AreEqual(pageIndex, list.PageIndex);
    }

    [TestMethod]
    public void Constructor_WithItems_AddsItemsToList()
    {
        // Arrange
        var items = new List<string> { "alpha", "beta", "gamma" };

        // Act
        var list = new PaginatedList<string>(items, 10, 1, 5);

        // Assert
        Assert.AreEqual(3, list.Count);
        Assert.AreEqual("alpha", list[0]);
        Assert.AreEqual("beta", list[1]);
        Assert.AreEqual("gamma", list[2]);
    }

    [TestMethod]
    [DataRow(1, 3, false, DisplayName = "Page 1 of 3 has no previous page")]
    [DataRow(2, 3, true, DisplayName = "Page 2 of 3 has previous page")]
    [DataRow(3, 3, true, DisplayName = "Page 3 of 3 has previous page")]
    public void HasPreviousPage_VariousPages_ReturnsExpected(int pageIndex, int totalPages, bool expected)
    {
        // Arrange
        var list = new PaginatedList<int>(new List<int>(), totalPages * 5, pageIndex, 5);

        // Act & Assert
        Assert.AreEqual(expected, list.HasPreviousPage);
    }

    [TestMethod]
    [DataRow(1, 3, true, DisplayName = "Page 1 of 3 has next page")]
    [DataRow(2, 3, true, DisplayName = "Page 2 of 3 has next page")]
    [DataRow(3, 3, false, DisplayName = "Page 3 of 3 has no next page")]
    public void HasNextPage_VariousPages_ReturnsExpected(int pageIndex, int totalPages, bool expected)
    {
        // Arrange
        var list = new PaginatedList<int>(new List<int>(), totalPages * 5, pageIndex, 5);

        // Act & Assert
        Assert.AreEqual(expected, list.HasNextPage);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
    }

    [TestMethod]
    public void Create_SecondPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(10, result[4]);
        Assert.AreEqual(2, result.PageIndex);
    }

    [TestMethod]
    public void Create_LastPagePartial_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 7).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.AreEqual(2, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(7, result[1]);
        Assert.AreEqual(2, result.TotalPages);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.AreEqual(1, result.PageIndex);
    }

    [TestMethod]
    public void TotalPages_ExactDivision_ReturnsCorrectValue()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int>(), 20, 1, 5);

        // Assert
        Assert.AreEqual(4, list.TotalPages);
    }

    [TestMethod]
    public void TotalPages_NotExactDivision_RoundsUp()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int>(), 21, 1, 5);

        // Assert
        Assert.AreEqual(5, list.TotalPages);
    }
}

