using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext _context;
    private HomeController _controller;

    [TestInitialize]
    public void Setup()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: $"HomeControllerTest_{Guid.NewGuid()}")
            .Options;
        _context = new SchoolContext(options);
        _controller = new HomeController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType(result, typeof(ViewResult));
    }

    [TestMethod]
    public void About_WithStudents_ReturnsEnrollmentDateGroups()
    {
        // Arrange
        var date1 = new DateTime(2023, 9, 1);
        var date2 = new DateTime(2022, 9, 1);
        _context.Students.AddRange(
            new Student { LastName = "Smith", FirstMidName = "John", EnrollmentDate = date1 },
            new Student { LastName = "Doe", FirstMidName = "Jane", EnrollmentDate = date1 },
            new Student { LastName = "Brown", FirstMidName = "Bob", EnrollmentDate = date2 }
        );
        _context.SaveChanges();

        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
        var group2023 = model.Single(g => g.EnrollmentDate == date1);
        Assert.AreEqual(2, group2023.StudentCount);
        var group2022 = model.Single(g => g.EnrollmentDate == date2);
        Assert.AreEqual(1, group2022.StudentCount);
    }

    [TestMethod]
    public void About_NoStudents_ReturnsEmptyList()
    {
        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void Contact_ReturnsViewWithMessage()
    {
        // Act
        var result = _controller.Contact() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
    }

    [TestMethod]
    public void Error_ReturnsViewResult()
    {
        // Act
        var result = _controller.Error();

        // Assert
        Assert.IsInstanceOfType(result, typeof(ViewResult));
    }

    [TestMethod]
    public void Unauthorized_ReturnsViewWithMessage()
    {
        // Act
        var result = _controller.Unauthorized() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
