    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: $"StudentsControllerTest_{Guid.NewGuid()}")
            .Options;
        _context = new SchoolContext(options);
        SeedStudents();
        _controller = new StudentsController(_context);
        // Set up HttpContext for ViewBag to work
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2010, 9, 1) },
            new Student { LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2012, 9, 1) },
            new Student { LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = new DateTime(2013, 9, 1) },
            new Student { LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = new DateTime(2012, 9, 1) },
            new Student { LastName = "Li", FirstMidName = "Yan", EnrollmentDate = new DateTime(2012, 9, 1) }
        );
        _context.SaveChanges();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void Index_NoParameters_ReturnsAllStudentsOrderedByLastName()
    {
