    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        // Drain any existing notifications first
        JsonResult drainResult;
        do
        {
            drainResult = _controller.GetNotifications();
        } while (GetPropertyValue<int>(drainResult.Value, "count") > 0);

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var success = GetPropertyValue<bool>(result.Value, "success");
        Assert.IsTrue(success);
        var count = GetPropertyValue<int>(result.Value, "count");
        Assert.AreEqual(0, count);
    }

    [TestMethod]
    public void GetNotifications_ReturnsJsonResult()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        Assert.IsInstanceOfType(result, typeof(JsonResult));
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        var success = GetPropertyValue<bool>(result.Value, "success");
        Assert.IsTrue(success);
    }

    [TestMethod]
    public void MarkAsRead_WithAnyId_ReturnsSuccess()
    {
        // Act (MarkAsRead is a no-op in this implementation)
        var result = _controller.MarkAsRead(999);

        // Assert
        Assert.IsNotNull(result);
        var success = GetPropertyValue<bool>(result.Value, "success");
        Assert.IsTrue(success);
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType(result, typeof(ViewResult));
    }

    // Helper to get property value from anonymous type
    private static T GetPropertyValue<T>(object obj, string propertyName)
    {
        var property = obj.GetType().GetProperty(propertyName);
        return (T)property.GetValue(obj);
    }
}

