    [TestMethod]
    [DataRow(".jpg", true, DisplayName = "jpg is allowed")]
    [DataRow(".jpeg", true, DisplayName = "jpeg is allowed")]
    [DataRow(".png", true, DisplayName = "png is allowed")]
    [DataRow(".gif", true, DisplayName = "gif is allowed")]
    [DataRow(".bmp", true, DisplayName = "bmp is allowed")]
    [DataRow(".pdf", false, DisplayName = "pdf is not allowed")]
    [DataRow(".exe", false, DisplayName = "exe is not allowed")]
    [DataRow(".txt", false, DisplayName = "txt is not allowed")]
    public void Create_Post_FileExtensionValidation_WorksCorrectly(string extension, bool isAllowed)
    {
        // Arrange
        var course = new Course
        {
            CourseID = 5555,
            Title = "TestCourse",
            Credits = 3,
            DepartmentID = 1
        };
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns($"file{extension}");
        mockFile.Setup(f => f.Length).Returns(1024);

        // Act
        var result = _controller.Create(course, mockFile.Object);

        // Assert
        if (!isAllowed)
        {
            Assert.IsInstanceOfType(result, typeof(ViewResult));
            Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }
        // If allowed, it will try to write to disk which may fail - that's fine, we're testing validation
    }
}

