    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        // Drain any existing notifications first
        JsonResult drainResult;
        do
        {
            drainResult = _controller.GetNotifications();
        } while (GetPropertyValue<int>(drainResult.Value, "count") > 0);

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var success = GetPropertyValue<bool>(result.Value, "success");
        Assert.IsTrue(success);
        var count = GetPropertyValue<int>(result.Value, "count");
        Assert.AreEqual(0, count);
    }

    [TestMethod]
    public void GetNotifications_ReturnsJsonResult()
    {
        // Act
